import{_ as t,o,c as a,a2 as r}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"Generated 3D assets","description":"","frontmatter":{},"headers":[],"relativePath":"guide/assets.md","filePath":"guide/assets.md","lastUpdated":1781997127000}'),s={name:"guide/assets.md"};function d(n,e,i,l,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="generated-3d-assets" tabindex="-1">Generated 3D assets <a class="header-anchor" href="#generated-3d-assets" aria-label="Permalink to &quot;Generated 3D assets&quot;">​</a></h1><p>Catalog of the game&#39;s generated 3D models. All models are produced <strong>per concrete character/prop ticket only</strong> (never speculatively — board directive <a href="/korovany/plan/game-plan">FLO-270</a>) via the <code>tools/meshy-3d</code> pipeline, in <strong>low-poly visual language v1.2</strong> (≤ 3000 tris/object, flat-shaded palette materials).</p><p>Files live under <code>public/models/*.glb</code> and stream into the scene through the <a href="./asset-streaming">asset-streaming</a> registry. Binaries are stored in <strong>Git LFS</strong> (see <code>.gitattributes</code>). Generation is reproducible from the recorded Meshy task id (<code>python tools/meshy-3d/meshy.py status &lt;task_id&gt; --kind text-to-3d</code>).</p><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><p>Generated assets are cleared for FlopBut&#39;s intended (incl. commercial) use under the Meshy paid-plan terms, which grant full commercial ownership of generated output. No infringing reference inputs are used, and these assets are kept out of any Community/showcase page.</p><h2 id="characters-props" tabindex="-1">Characters &amp; props <a class="header-anchor" href="#characters-props" aria-label="Permalink to &quot;Characters &amp; props&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>File</th><th>Tris</th><th>Size</th><th>Rig</th><th>Meshy task id</th></tr></thead><tbody><tr><td>Player hero (elf)</td><td><code>public/models/korovany_hero_player-default.glb</code></td><td>2894</td><td>—</td><td>static (no skeleton)</td><td>—</td></tr><tr><td>Conifer tree</td><td><code>public/models/forest-tree.glb</code></td><td>1357</td><td>—</td><td>static</td><td>—</td></tr><tr><td>Wooden hut</td><td><code>public/models/wooden-hut.glb</code></td><td>1893</td><td>—</td><td>static</td><td>—</td></tr><tr><td>Chest</td><td><code>public/models/chest.glb</code></td><td>—</td><td>—</td><td>static</td><td>—</td></tr><tr><td><strong>Empire soldier (enemy)</strong></td><td><code>public/models/empire-soldier.glb</code></td><td><strong>2794</strong></td><td>130 KiB</td><td>static (no skeleton)</td><td><code>019ee601-93f0-7988-86f8-e35ce1067881</code></td></tr><tr><td><strong>Roadside shrine (Salt Road)</strong></td><td><code>public/models/roadside-shrine.glb</code></td><td><strong>1984</strong></td><td>394 KiB</td><td>static</td><td><code>019ee73a-c8a6-73bd-a2ec-e21137a6dba2</code> (preview) / <code>019ee747-ae35-786a-a8c7-490e65d0cddd</code> (retexture)</td></tr><tr><td><strong>Empire toll gate</strong></td><td><code>public/models/toll-gate.glb</code></td><td><strong>1947</strong></td><td>4.1 MiB</td><td>static</td><td>preview <code>019ee748-205e-763a-a883-bdda11e91c7e</code> · retexture <code>019ee749-ae59-7680-aa94-e6a8842c7bd5</code></td></tr><tr><td><strong>Caravan wagon (Salt Road)</strong></td><td><code>public/models/caravan-wagon.glb</code></td><td><strong>2827</strong></td><td>394 KiB</td><td>static</td><td><code>019ee749-d4cf-79b9-b813-d98be2201197</code> (preview) / <code>019ee74d-2300-772c-8a22-612c27dd99dc</code> (retexture)</td></tr><tr><td><strong>Ruined watchtower (Salt Road)</strong></td><td><code>public/models/watchtower.glb</code></td><td><strong>2564</strong></td><td>379 KiB</td><td>static</td><td><code>019ee749-6051-7990-b286-98be4ecf82b4</code> (retexture)</td></tr></tbody></table><h3 id="empire-toll-gate-—-phase-3-5-salt-road-pack" tabindex="-1">Empire toll gate — Phase 3.5 (Salt Road pack) <a class="header-anchor" href="#empire-toll-gate-—-phase-3-5-salt-road-pack" aria-label="Permalink to &quot;Empire toll gate — Phase 3.5 (Salt Road pack)&quot;">​</a></h3><p>Salt Road landmark and navigation anchor (world-specs.md §1). Generated for <a href="/korovany/FLO/issues/FLO-373">FLO-373</a>.</p><ul><li><strong>Budget:</strong> 1947 tris ≤ 2500 (v1.2). Bounding box ≈ 2.0 × 1.6 × 0.7 units (road-spanning prop). Textured (retexture pass).</li><li><strong>Provenance:</strong> Meshy text-to-3D preview at <code>--target-polycount 2000 --art-style realistic</code>, followed by retexture pass. Prompt: <em>&quot;low-poly stylized empire toll gate, two wooden barrier arms across a road, small wooden ledger booth, tall flagpole with imperial banner, weathered wood and iron, faceted flat-shaded, austere straight imperial design, readable silhouette&quot;</em>. Retexture style: <em>&quot;weathered wood planks, rusted iron fittings, imperial red and gold banner, stone road surface, earthy tones, flat low-poly colors&quot;</em>. 20 preview + 10 retexture = 30 Meshy credits.</li><li><strong>Rig:</strong> static mesh, no skeleton.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/toll-gate.glb</code> → 2 meshes, 1947 tris, no errors.</li><li><strong>Handoff:</strong> scene wiring (replacing the placeholder box in <code>humanLandsScene.ts</code>) is engineering scope — see <a href="/korovany/FLO/issues/FLO-373">FLO-373</a>.</li></ul><h3 id="ruined-watchtower-salt-road-landmark-—-phase-3-5-mpg" tabindex="-1">Ruined watchtower (Salt Road landmark) — Phase 3.5 / MPG <a class="header-anchor" href="#ruined-watchtower-salt-road-landmark-—-phase-3-5-mpg" aria-label="Permalink to &quot;Ruined watchtower (Salt Road landmark) — Phase 3.5 / MPG&quot;">​</a></h3><p>Tall round ruined stone tower, 3–4 stories, two crenellated tiers, a doorway at the base and a rubble skirt — a strong vertical silhouette to serve as a navigation anchor on the Velya Salt Road (<a href="./worlds/velya-salt-road">world-specs</a>, <code>world-specs.md</code> landmark list). Generated for <a href="/korovany/plan/game-plan">FLO-374</a>; replaces the placeholder colored box in <code>src/scenes/humanLandsScene.ts</code>.</p><ul><li><strong>Budget:</strong> 2564 tris — 64 over the per-asset 2500 target but within the binding v1.2 cap (≤ 3000 tris/object). Kept the clean retextured mesh rather than decimating a <em>textured</em> model (post-texture <code>simplify</code> risks UV-seam artifacts; this is a single static landmark, not an instanced prop, so the 2.5% overage costs nothing at runtime). Bounding box ≈ 1.12 × 2.0 × 1.12 Meshy units — engineering should scale it up in-scene to read as a 3–4 story tower (real-world ≈ 10–14 m tall); up-axis +Y, pivot at base centre.</li><li><strong>Textured (board mandate — not grey):</strong> weathered pale grey stone with cracked stonework, baked into a single 1024² base-color map (JPEG, lighting removed for flat low-poly shading). Geometry-preserving <strong>Meshy retexture</strong> (preferred over PBR refine for low-poly), then textures resized 3.6 MB → 241 KiB via <code>tools/meshy-3d/resize_glb_textures.py --max 1024 --quality 85</code>, taking the GLB from 3.7 MB to <strong>379 KiB</strong> for the web payload budget.</li><li><strong>Provenance:</strong> Meshy text-to-3D preview → retexture. <ul><li>Preview prompt: <em>&quot;low-poly stylized ruined stone watchtower, tall round tower 3-4 stories, cracked broken stonework, partly collapsed top, weathered pale grey stone, faceted flat-shaded, strong vertical silhouette visible from distance, fantasy ruin&quot;</em>.</li><li>Retexture style prompt: <em>&quot;weathered pale grey stone, faceted flat-shaded low-poly, dusty sun-bleached fantasy ruin, cracked broken stonework, muted earthy palette&quot;</em>. Retexture task id <code>019ee749-6051-7990-b286-98be4ecf82b4</code>, 10 Meshy credits.</li></ul></li><li><strong>Rig:</strong> ships <strong>static</strong> (no skeleton) — it is scenery, not animated.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/watchtower.glb</code> → 2 meshes, 2564 tris, no errors.</li><li><strong>Handoff:</strong> wiring the GLB into the scene (replacing the procedural watchtower box at <code>humanLandsScene.ts:60</code>) is engineering&#39;s job — for Daedalus/CTO, not done here.</li></ul><h3 id="empire-soldier-enemy-—-phase-2" tabindex="-1">Empire soldier (enemy) — Phase 2 <a class="header-anchor" href="#empire-soldier-enemy-—-phase-2" aria-label="Permalink to &quot;Empire soldier (enemy) — Phase 2&quot;">​</a></h3><p>Napoleonic-era Empire infantryman: bicorne hat, greatcoat, boots, musket held across the body. Generated for <a href="/korovany/plan/game-plan">FLO-311</a> (feeds the enemy-NPC ticket E2.3).</p><ul><li><strong>Budget:</strong> 2794 tris ≤ 3000 (v1.2). Bounding box ≈ 0.97 × 1.90 × 0.84 units (humanoid, ~1.9 tall). Preview-only — no PBR textures (refine is skipped for v1.2; PBR refine drifts the faceted low-poly look into a semi-realistic band).</li><li><strong>Provenance:</strong> Meshy text-to-3D preview, <code>--art-style realistic --target-polycount 3000</code>. Prompt: <em>&quot;low-poly stylized empire soldier enemy, humanoid game character standing in a neutral A-pose, military uniform with peaked helmet and boots, holding a musket rifle, faceted flat-shaded surfaces, muted grey-green palette, full body, single character&quot;</em>. Meshy emitted 3105 tris; welded + decimated to 2794 with <code>gltf-transform</code> (<code>weld</code> → <code>simplify --ratio 0.9 --error 0.01</code>) to fit the budget — silhouette/bbox unchanged. 20 Meshy credits (preview only).</li><li><strong>Rig:</strong> ships <strong>unrigged (static mesh, no skeleton/animation clips)</strong> — this matches the player hero GLB, which is also a static mesh, so the same loader / controller code handles it without special-casing. There is <strong>no hero rig to reuse</strong> (hero has 0 skeletons). E2.3 must therefore drive idle/walk/attack/death either procedurally (transform-level) or by adding a skeletal rig in a separate pass (Meshy auto-rigging is available but was out of scope for this asset-only ticket). Flag rig needs to Pygmalion if a skeletal pass is wanted.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/empire-soldier.glb</code> → 2 meshes, 2794 tris, no errors.</li></ul><h3 id="roadside-shrine-salt-road-—-phase-3-5-mpg" tabindex="-1">Roadside shrine (Salt Road) — Phase 3.5 (MPG) <a class="header-anchor" href="#roadside-shrine-salt-road-—-phase-3-5-mpg" aria-label="Permalink to &quot;Roadside shrine (Salt Road) — Phase 3.5 (MPG)&quot;">​</a></h3><p>Humble rural Salt Road landmark (<a href="/korovany/plan/world-specs">world-specs</a> §1), replacing the placeholder colored box in <code>src/scenes/humanLandsScene.ts</code>. Small weathered stone structure with an arched niche, aged-wood back, and a low offering ledge — a readable, distinct silhouette. Generated for <a href="/korovany/plan/game-plan">FLO-375</a>.</p><ul><li><strong>Budget:</strong> 1984 tris ≤ 2000 (within ticket budget), <strong>394 KiB</strong> web payload. Bounding box ≈ 1.52 × 2.00 × 1.15 units (real-world scale, ~2 m tall).</li><li><strong>Textured</strong> (board mandate — never grey): single 1024² base-color map, flat/unlit albedo (worn pale stone with moss accents + aged grey-brown wood).</li><li><strong>Provenance:</strong> Meshy text-to-3D <strong>preview</strong> (<code>019ee73a-…</code>, geometry only, 1985 tris, 20 cr) → <strong>retexture</strong> (<code>019ee747-…</code>, geometry-preserving UV-unwrap <ul><li>paint, 10 cr) → <code>resize_glb_textures.py --max 1024 --quality 85</code> (4.3 MiB → 394 KiB, mesh bytes untouched). Retexture over PBR refine keeps the faceted low-poly silhouette (<a href="#">meshy PBR drift</a> — see <code>API-FITNESS.md</code>). Prompt: <em>&quot;low-poly stylized roadside shrine, small weathered stone structure with an arched niche, simple offering ledge, worn pale stone and aged wood, faceted flat-shaded, humble rural fantasy aesthetic, readable silhouette&quot;</em>; retexture style prompt: <em>&quot;worn pale weathered stone shrine with aged grey-brown wood, humble rural fantasy, flat low-poly muted earthy palette, faceted unlit albedo&quot;</em>.</li></ul></li><li><strong>Rig:</strong> static prop — no skeleton.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/roadside-shrine.glb</code> → 2 meshes, 1984 tris, 1 embedded texture, no errors.</li><li><strong>Handoff:</strong> wiring this GLB into the scene (replacing the procedural box in <code>humanLandsScene.ts</code>) is engineering&#39;s job — handed to Daedalus/CTO.</li></ul><h3 id="caravan-wagon-salt-road-—-phase-3-5-mpg" tabindex="-1">Caravan wagon (Salt Road) — Phase 3.5 (MPG) <a class="header-anchor" href="#caravan-wagon-salt-road-—-phase-3-5-mpg" aria-label="Permalink to &quot;Caravan wagon (Salt Road) — Phase 3.5 (MPG)&quot;">​</a></h3><p>The raid-loop centerpiece (&quot;грабить корованы&quot;, E3.3; MPG.5 spawns caravans across forest + human-lands). Replaces the procedural brown box stand-in in <code>src/scenes/caravanEnemy.ts</code> (~line 94, <code>CreateBox 1.6 × 1.2 × 2.4</code>). Merchant wagon with a wooden frame, fabric canopy cover, four spoked wheels and a cargo bed — a readable wagon silhouette turns the abstract crate into a tactile target. Generated for <a href="/korovany/plan/game-plan">FLO-371</a>.</p><ul><li><strong>Budget:</strong> 2827 tris ≤ 3000 (v1.2), <strong>394 KiB</strong> web payload. Bounding box ≈ 2.00 × 1.69 × 1.09 units (real-world scale; wagon length runs along <strong>+X</strong>). Note for wiring: the placeholder box is <code>1.6 (w) × 1.2 (h) × 2.4 (d)</code> with the long axis on <strong>Z</strong> — engineering should rotate ~90° about Y and scale to taste so the wagon length aligns with the caravan&#39;s travel axis.</li><li><strong>Textured</strong> (board mandate — never grey): single 1024² base-color map, flat/unlit albedo (weathered tan-brown wood, off-white travel-worn canopy, dark iron-banded wheels).</li><li><strong>Provenance:</strong> Meshy text-to-3D <strong>preview</strong> (<code>019ee749-…</code>, <code>--art-style realistic --target-polycount 3000</code>, 3042 tris, 5 cr) → <code>gltf-transform</code> weld + <code>simplify --ratio 0.93 --error 0.01</code> to 2827 tris (silhouette/bbox unchanged) → <strong>retexture</strong> (<code>019ee74d-…</code>, geometry-preserving UV-unwrap + paint of the decimated mesh via data-URI, 10 cr) → <code>resize_glb_textures.py --max 1024 --quality 85</code> (3.6 MiB → 394 KiB, mesh bytes untouched). Retexture over PBR refine keeps the faceted low-poly silhouette. Preview prompt: <em>&quot;low-poly stylized merchant wagon, wooden frame with fabric canopy cover, four spoked wooden wheels, weathered travel-worn wood and cloth, faceted flat-shaded, neutral tan-brown palette, readable side and front silhouette, fantasy medieval cargo wagon&quot;</em>; retexture style prompt: <em>&quot;weathered tan-brown wooden wagon frame, off-white travel-worn fabric canopy cover, dark iron-banded wheel rims, flat muted low-poly colors, no gloss, fantasy medieval merchant cargo wagon&quot;</em>.</li><li><strong>Rig:</strong> static prop — no skeleton.</li><li><strong>Verification:</strong> loads headless via <code>node tools/meshy-3d/smoke_load_glb.mjs public/models/caravan-wagon.glb</code> → 2 meshes, 2827 tris, 1 embedded texture, no errors.</li><li><strong>Handoff:</strong> wiring this GLB into the scene (replacing the procedural box in <code>caravanEnemy.ts</code>) is engineering&#39;s job — handed to Daedalus/CTO.</li></ul>',22)])])}const u=t(s,[["render",d]]);export{p as __pageData,u as default};
